def _seed_ch2_notes_inner(conn, db_exec, row_to_dict, USE_POSTGRES, force=False):
    ph = '%s' if USE_POSTGRES else '?'
    try:
        conn.execute("""CREATE TABLE IF NOT EXISTS study_notes (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            subject TEXT NOT NULL DEFAULT 'GK',
            topic TEXT NOT NULL DEFAULT 'Indian_History',
            chapter_num INTEGER NOT NULL,
            chapter_title_te TEXT NOT NULL DEFAULT '',
            chapter_title_en TEXT NOT NULL DEFAULT '',
            pages_ref TEXT DEFAULT '',
            sections_json TEXT NOT NULL DEFAULT '[]',
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )""")
        if USE_POSTGRES: conn.commit()
    except Exception: pass

    cur = db_exec(conn, f"SELECT id FROM study_notes WHERE chapter_num={ph} AND subject={ph}", (2, 'GK'))
    row = cur.fetchone()
    if row and not force:
        return {'success': False, 'already_exists': True,
                'message': 'Chapter 2 notes already seeded. Use force=True to overwrite.'}
    if row and force:
        db_exec(conn, f"DELETE FROM study_notes WHERE chapter_num={ph} AND subject={ph}", (2, 'GK'))
    if USE_POSTGRES: conn.commit()

    db_exec(conn,
        f"INSERT INTO study_notes (subject, topic, subtopic, chapter_num, chapter_title_te, chapter_title_en, pages_ref, sections_json) "
        f"VALUES ({ph},{ph},{ph},{ph},{ph},{ph},{ph})",
        ('GK', 'Indian_History', 'Ancient', 2,
         'పూర్వచారిత్రక సంస్కృతులు', 'Pre-Historic Cultures',
         '7-20', _json.dumps(SECTIONS_JSON, ensure_ascii=False)))
    if USE_POSTGRES: conn.commit()
    return {'success': True, 'message': 'Chapter 2 notes seeded successfully! (20 sections)', 'total': 20}


def _seed_ch2_mcqs_inner(conn, db_exec, row_to_dict, USE_POSTGRES):
    ph = '%s' if USE_POSTGRES else '?'
    cur = db_exec(conn, f"SELECT id FROM study_notes WHERE chapter_num={ph} AND subject={ph}", (2, 'GK'))
    row = cur.fetchone()
    if not row:
        _seed_ch2_notes_inner(conn, db_exec, row_to_dict, USE_POSTGRES, force=False)
        cur = db_exec(conn, f"SELECT id FROM study_notes WHERE chapter_num={ph} AND subject={ph}", (2, 'GK'))
        row = cur.fetchone()
    note_id = row_to_dict(row)['id']
    db_exec(conn, f"DELETE FROM chapter_mcqs WHERE study_note_id={ph}", (note_id,))
    insert_sql = (
        f"INSERT INTO chapter_mcqs "
        f"(study_note_id, section_idx, difficulty, q_te, opt_a, opt_b, opt_c, opt_d, correct, explanation_te) "
        f"VALUES ({ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph},{ph})"
    )
    for (sec_idx, diff, q_te, a, b, c, d, correct, expl) in MCQ_DATA:
        db_exec(conn, insert_sql, (note_id, sec_idx, diff, q_te, a, b, c, d, str(correct).lower(), expl))
    if USE_POSTGRES: conn.commit()
    easy   = sum(1 for m in MCQ_DATA if m[1]==1)
    medium = sum(1 for m in MCQ_DATA if m[1]==2)
    hard   = sum(1 for m in MCQ_DATA if m[1]==3)
    return {'success': True,
             'message': f'Chapter 2 MCQs seeded successfully! Total: {len(MCQ_DATA)} questions.',
             'inserted': len(MCQ_DATA), 'total': len(MCQ_DATA),
             'easy': easy, 'medium': medium, 'hard': hard}
